// Nur Emails mit Attachments verarbeiten
// Unterstuetzte Dateitypen filtern
const items = $input.all();
const supportedTypes = ['.pdf', '.docx', '.doc', '.txt', '.md', '.xlsx', '.pptx', '.odt', '.ods', '.csv'];
const results = [];

for (const item of items) {
  const binaries = item.binary || {};
  const subject = item.json.subject || '(kein Betreff)';
  const from = item.json.from?.text || item.json.from || 'unbekannt';
  const messageId = item.json.messageId || item.json.id || `email-${Date.now()}`;
  const date = item.json.date || new Date().toISOString();

  // Jedes Attachment einzeln verarbeiten
  for (const [key, binary] of Object.entries(binaries)) {
    const fileName = binary.fileName || key;
    const ext = fileName.substring(fileName.lastIndexOf('.')).toLowerCase();

    if (!supportedTypes.includes(ext)) continue;

    results.push({
      json: {
        fileName: fileName,
        fileExtension: ext,
        emailSubject: subject,
        emailFrom: from,
        emailDate: date,
        source: 'email',
        source_id: `${messageId}__${fileName}`,
        binaryKey: key,
        action: 'add_or_update'
      },
      binary: { data: binary }
    });
  }
}

if (results.length === 0) {
  return [{ json: { action: 'none', reason: 'Keine unterstuetzten Attachments' } }];
}

return results;

// Text aus Attachment extrahieren
const item = $input.first();
const ext = item.json.fileExtension;
let text = '';
let needs_ocr = false;

if (ext === '.txt' || ext === '.md' || ext === '.csv') {
  const binaryData = item.binary?.data;
  if (binaryData) {
    text = Buffer.from(binaryData.data, 'base64').toString('utf-8');
  }
} else if (ext === '.pdf') {
  text = '[PDF_BINARY]';
  needs_ocr = true;
} else if (ext === '.docx' || ext === '.odt') {
  text = '[NEEDS_EXTRACTION]';
} else {
  text = '[UNSUPPORTED_FORMAT]';
}

if (text.length > 0 && text.length < 50 && !text.startsWith('[')) {
  needs_ocr = true;
  text = '[OCR_NEEDED] ' + text;
}

// Email-Metadaten als Kontext prependen
const context = `Quelle: Email von ${item.json.emailFrom}\nBetreff: ${item.json.emailSubject}\nDatum: ${item.json.emailDate}\nDatei: ${item.json.fileName}\n---\n`;

return [{
  json: {
    ...item.json,
    text: context + text,
    needs_ocr: needs_ocr
  },
  binary: item.binary
}];

// Chunking (identisch zu Nextcloud/Drive Workflow)
const item = $input.first();
const text = item.json.text;
const CHUNK_SIZE = parseInt($env.CHUNK_SIZE || '500');
const CHUNK_OVERLAP = parseInt($env.CHUNK_OVERLAP || '75');

if (!text || text.startsWith('[') || text.length < 50) {
  return [{ json: { ...item.json, chunks: [text], chunkCount: 1 } }];
}

const chunks = [];
let start = 0;

while (start < text.length) {
  let end = Math.min(start + CHUNK_SIZE, text.length);

  if (end < text.length) {
    const lastPeriod = text.lastIndexOf('. ', end);
    const lastNewline = text.lastIndexOf('\n', end);
    const bestBreak = Math.max(lastPeriod, lastNewline);
    if (bestBreak > start + CHUNK_SIZE * 0.5) {
      end = bestBreak + 1;
    }
  }

  const chunk = text.substring(start, end).trim();
  if (chunk.length > 0) chunks.push(chunk);

  start = end - CHUNK_OVERLAP;
  if (start >= text.length) break;
}

return [{ json: { ...item.json, chunks, chunkCount: chunks.length } }];

// Embedding + Supabase (identisch zu Nextcloud Workflow)
const item = $input.first();
const chunks = item.json.chunks;
const supabaseUrl = $env.SUPABASE_URL;
const supabaseKey = $env.SUPABASE_SERVICE_ROLE_KEY;
const tenantId = $env.TENANT_ID || 'clx-digital';
const ollamaUrl = $env.OLLAMA_BASE_URL || 'http://host.docker.internal:11434';
const embeddingModel = $env.EMBEDDING_MODEL || 'nomic-embed-text';

// Alte Chunks loeschen (idempotent)
await fetch(`${supabaseUrl}/rest/v1/rpc/delete_by_source_id`, {
  method: 'POST',
  headers: {
    'apikey': supabaseKey,
    'Authorization': `Bearer ${supabaseKey}`,
    'Content-Type': 'application/json'
  },
  body: JSON.stringify({ p_source: 'email', p_source_id: item.json.source_id })
});

const results = [];
for (let i = 0; i < chunks.length; i++) {
  const chunk = chunks[i];

  const embResp = await fetch(`${ollamaUrl}/api/embeddings`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ model: embeddingModel, prompt: chunk })
  });
  const embData = await embResp.json();

  if (embData.embedding) {
    await fetch(`${supabaseUrl}/rest/v1/documents`, {
      method: 'POST',
      headers: {
        'apikey': supabaseKey,
        'Authorization': `Bearer ${supabaseKey}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal'
      },
      body: JSON.stringify({
        source: 'email',
        source_id: item.json.source_id,
        file_name: item.json.fileName,
        file_path: `${item.json.emailFrom} — ${item.json.emailSubject}`,
        content: chunk,
        chunk_index: i,
        embedding: `[${embData.embedding.join(',')}]`,
        tenant_id: tenantId,
        metadata: {
          emailFrom: item.json.emailFrom,
          emailSubject: item.json.emailSubject,
          emailDate: item.json.emailDate
        }
      })
    });
    results.push({ chunk: i, status: 'ok' });
  }

  if (i < chunks.length - 1) await new Promise(r => setTimeout(r, 500));
}

return [{ json: { fileName: item.json.fileName, chunksInserted: results.length } }];
